import json
import urllib.request
import urllib.error
import urllib.parse
import ssl
import re


# Configuration constants
MAX_ENRICH_URLS = 3
MAX_URL_LENGTH = 2048
REQUEST_TIMEOUT_SECONDS = 2
MAX_RESPONSE_SIZE = 8192  # 8KB max response per enrichment URL
ALLOWED_SCHEMES = {'https'}
ALLOWED_CONTENT_TYPES = {'application/json', 'text/plain'}
# Allowlist of domains that can be fetched for enrichment
ALLOWED_DOMAINS = {
    'api.example.com',
    'enrichment.example.com',
    'data.example.com',
}
# Block private/internal IP ranges via domain validation
BLOCKED_DOMAIN_PATTERNS = [
    re.compile(r'^localhost$', re.IGNORECASE),
    re.compile(r'^127\.', re.IGNORECASE),
    re.compile(r'^10\.', re.IGNORECASE),
    re.compile(r'^172\.(1[6-9]|2[0-9]|3[01])\.', re.IGNORECASE),
    re.compile(r'^192\.168\.', re.IGNORECASE),
    re.compile(r'^\[?::1\]?$', re.IGNORECASE),
    re.compile(r'^\[?fd[0-9a-f]{2}:', re.IGNORECASE),
    re.compile(r'^169\.254\.', re.IGNORECASE),
    re.compile(r'^0\.', re.IGNORECASE),
]


def validate_url(url_string):
    """
    Validate that a URL is safe to fetch.
    Returns the parsed URL if valid, raises ValueError otherwise.
    """
    if not url_string or not isinstance(url_string, str):
        raise ValueError("URL must be a non-empty string")

    if len(url_string) > MAX_URL_LENGTH:
        raise ValueError(f"URL exceeds maximum length of {MAX_URL_LENGTH}")

    # Strip whitespace
    url_string = url_string.strip()

    parsed = urllib.parse.urlparse(url_string)

    # Validate scheme - HTTPS only
    if parsed.scheme not in ALLOWED_SCHEMES:
        raise ValueError(f"URL scheme '{parsed.scheme}' not allowed. Only {ALLOWED_SCHEMES} permitted.")

    # Extract hostname
    hostname = parsed.hostname
    if not hostname:
        raise ValueError("URL must contain a valid hostname")

    # Check against blocked domain patterns (SSRF prevention)
    for pattern in BLOCKED_DOMAIN_PATTERNS:
        if pattern.match(hostname):
            raise ValueError(f"URL hostname '{hostname}' is blocked (private/internal address)")

    # Check domain allowlist
    if hostname not in ALLOWED_DOMAINS:
        raise ValueError(f"URL hostname '{hostname}' is not in the allowed domains list")

    # Disallow userinfo in URL (potential SSRF vector)
    if parsed.username or parsed.password:
        raise ValueError("URLs with userinfo (username/password) are not allowed")

    # Validate port if specified
    if parsed.port and parsed.port not in (443,):
        raise ValueError(f"Port {parsed.port} is not allowed. Only port 443 is permitted.")

    return url_string


def safe_fetch(url, timeout=REQUEST_TIMEOUT_SECONDS):
    """
    Safely fetch content from a validated URL with size limits and timeout.
    Returns a dict with status, content_type, and body.
    """
    validated_url = validate_url(url)

    # Create SSL context that verifies certificates
    ssl_context = ssl.create_default_context()

    req = urllib.request.Request(
        validated_url,
        method='GET',
        headers={
            'User-Agent': 'LambdaEdge-Enrichment/1.0',
            'Accept': 'application/json, text/plain',
        }
    )

    try:
        with urllib.request.urlopen(req, timeout=timeout, context=ssl_context) as response:
            status_code = response.getcode()

            # Validate content type
            content_type = response.headers.get('Content-Type', '')
            base_content_type = content_type.split(';')[0].strip().lower()
            if base_content_type not in ALLOWED_CONTENT_TYPES:
                return {
                    'status': 'error',
                    'error': f'Disallowed content type: {base_content_type}'
                }

            # Check Content-Length header if available
            content_length = response.headers.get('Content-Length')
            if content_length and int(content_length) > MAX_RESPONSE_SIZE:
                return {
                    'status': 'error',
                    'error': f'Response too large: {content_length} bytes'
                }

            # Read with size limit
            body = response.read(MAX_RESPONSE_SIZE + 1)
            if len(body) > MAX_RESPONSE_SIZE:
                return {
                    'status': 'error',
                    'error': f'Response exceeded max size of {MAX_RESPONSE_SIZE} bytes'
                }

            body_str = body.decode('utf-8', errors='replace')

            # If JSON, validate it parses correctly
            if base_content_type == 'application/json':
                try:
                    json.loads(body_str)
                except json.JSONDecodeError:
                    return {
                        'status': 'error',
                        'error': 'Invalid JSON in response'
                    }

            return {
                'status': 'success',
                'http_status': status_code,
                'content_type': base_content_type,
                'body': body_str,
            }

    except urllib.error.HTTPError as e:
        return {
            'status': 'error',
            'http_status': e.code,
            'error': f'HTTP error: {e.code} {e.reason}'
        }
    except urllib.error.URLError as e:
        return {
            'status': 'error',
            'error': f'URL error: {str(e.reason)}'
        }
    except ssl.SSLError as e:
        return {
            'status': 'error',
            'error': f'SSL error: {str(e)}'
        }
    except Exception as e:
        return {
            'status': 'error',
            'error': f'Fetch error: {type(e).__name__}'
        }


def sanitize_header_value(value, max_length=4096):
    """
    Sanitize a string for safe inclusion as an HTTP header value.
    Remove control characters and limit length.
    """
    if not value:
        return ''
    # Remove control characters except space and tab
    sanitized = ''.join(
        c for c in value if c == '\t' or (ord(c) >= 32 and ord(c) < 127)
    )
    return sanitized[:max_length]


def get_header_value(headers, header_name):
    """
    Extract a header value from CloudFront headers structure (case-insensitive).
    """
    lower_name = header_name.lower()
    if lower_name in headers:
        header_entries = headers[lower_name]
        if header_entries and len(header_entries) > 0:
            return header_entries[0].get('value', '')
    return None


def lambda_handler(event, context):
    """
    Lambda@Edge viewer request handler.
    
    Reads X-Enrich-URL headers (comma-separated URLs), fetches data from
    each allowed URL, and adds enrichment data as headers before forwarding
    to origin.
    """
    try:
        request = event['Records'][0]['cf']['request']
        headers = request.get('headers', {})

        # Extract enrichment URLs from header
        enrich_header = get_header_value(headers, 'x-enrich-url')

        if not enrich_header:
            # No enrichment requested, pass through
            # Remove the header to prevent it from reaching origin
            headers.pop('x-enrich-url', None)
            return request

        # Parse comma-separated URLs
        raw_urls = [u.strip() for u in enrich_header.split(',') if u.strip()]

        # Limit number of URLs to prevent abuse
        if len(raw_urls) > MAX_ENRICH_URLS:
            raw_urls = raw_urls[:MAX_ENRICH_URLS]

        enrichment_results = {}
        enrichment_errors = []

        for idx, url in enumerate(raw_urls):
            try:
                result = safe_fetch(url)
                if result['status'] == 'success':
                    enrichment_results[f'enrich_{idx}'] = result['body']
                else:
                    enrichment_errors.append(
                        f"URL {idx}: {result.get('error', 'unknown error')}"
                    )
            except ValueError as ve:
                enrichment_errors.append(f"URL {idx}: validation failed - {str(ve)}")
            except Exception:
                enrichment_errors.append(f"URL {idx}: unexpected error")

        # Remove the original enrichment header to prevent forwarding to origin
        headers.pop('x-enrich-url', None)

        # Add enrichment data as headers
        if enrichment_results:
            # Combine all enrichment data into a single JSON header
            enrichment_json = json.dumps(enrichment_results, ensure_ascii=True)
            sanitized_value = sanitize_header_value(enrichment_json)

            # Lambda@Edge has header size limits (~8KB for viewer request)
            if len(sanitized_value) <= 8000:
                headers['x-enrichment-data'] = [{
                    'key': 'X-Enrichment-Data',
                    'value': sanitized_value
                }]

            headers['x-enrichment-count'] = [{
                'key': 'X-Enrichment-Count',
                'value': str(len(enrichment_results))
            }]

        # Add error information if any
        if enrichment_errors:
            error_summary = sanitize_header_value(
                json.dumps(enrichment_errors, ensure_ascii=True),
                max_length=1024
            )
            headers['x-enrichment-errors'] = [{
                'key': 'X-Enrichment-Errors',
                'value': error_summary
            }]

        # Add enrichment status header
        if enrichment_results and not enrichment_errors:
            status = 'complete'
        elif enrichment_results and enrichment_errors:
            status = 'partial'
        else:
            status = 'failed'

        headers['x-enrichment-status'] = [{
            'key': 'X-Enrichment-Status',
            'value': status
        }]

        request['headers'] = headers
        return request

    except KeyError as e:
        # If the event structure is unexpected, return the request as-is
        # This shouldn't happen with valid CloudFront events
        try:
            request = event['Records'][0]['cf']['request']
            return request
        except (KeyError, IndexError):
            # Return a 502 if we can't even parse the request
            return {
                'status': '502',
                'statusDescription': 'Bad Gateway',
                'body': 'Internal edge processing error',
            }
    except Exception:
        # Fail open - return the original request without enrichment
        try:
            request = event['Records'][0]['cf']['request']
            # Clean up any enrichment headers
            request.get('headers', {}).pop('x-enrich-url', None)
            return request
        except (KeyError, IndexError):
            return {
                'status': '502',
                'statusDescription': 'Bad Gateway',
                'body': 'Internal edge processing error',
            }